"// Serve Page Builder static files and index
// When accessed with mode=embed, serve the page builder for iframe embedding.
// When accessed directly (no mode=embed), redirect to the unified customizer.
app.use('/page-builder', (req, res, next) => {
  // Allow static file requests (JS, CSS, images, etc.) to pass through
  if (req.path !== '/' && req.path !== '') {
    return express.static(path.join(__dirname, '..', 'page-builder'))(req, res, next);
  }
  // Check if this is an embed request (from customizer iframe)
  if (req.query.mode === 'embed') {
    return res.sendFile(path.join(__dirname, '..', 'page-builder', 'index.html'));
  }
  // Direct navigation — redirect to the unified customizer
  res.redirect('/admin?module=customizer&tab=pages');
});"

